  `duration_in_hours` float DEFAULT NULL,
  `is_doubleheader` tinyint DEFAULT NULL,
  `is_spring` tinyint DEFAULT NULL,
  `is_scrimmage` tinyint DEFAULT NULL,
  `umpire_override` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`ID`)
) ENGINE=InnoDB AUTO_INCREMENT=2573 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
